printWindow.document.write(`
  <!DOCTYPE html>
  <html dir="rtl" lang="ar">
  <head>
    <meta charset="UTF-8">
    <title>تقرير الحضور الشهري - ${escapeHtml(employee.name)}</title>
    <style>
      * { box-sizing: border-box; margin: 0; padding: 0; }
      @page { 
        size: A4 portrait; 
        margin: 8mm; 
      }
      body { 
        font-family: 'Segoe UI', Tahoma, Arial, sans-serif; 
        padding: 5px; 
        direction: rtl;
        font-size: 9px;
        line-height: 1.2;
      }
      .header { 
        text-align: center; 
        border-bottom: 2px solid #2563eb; 
        padding-bottom: 5px; 
        margin-bottom: 8px;
      }
      .header h1 { color: #1e40af; font-size: 16px; margin-bottom: 2px; }
      .header p { color: #6b7280; font-size: 11px; }
      .employee-info {
        display: grid;
        grid-template-columns: repeat(4, 1fr);
        gap: 5px;
        margin-bottom: 8px;
        padding: 6px;
        background: #f8fafc;
        border-radius: 4px;
        border: 1px solid #e2e8f0;
      }
      .employee-info div { text-align: center; }
      .employee-info strong { display: block; color: #374151; font-size: 8px; }
      .employee-info span { font-size: 10px; font-weight: 600; color: #1f2937; }
      table { 
        width: 100%; 
        border-collapse: collapse; 
        margin-top: 5px;
        font-size: 8px;
      }
      th, td { 
        border: 1px solid #d1d5db; 
        padding: 2px 3px; 
        text-align: center; 
      }
      th { 
        background: #2563eb; 
        color: white; 
        font-weight: 600;
        font-size: 8px;
      }
      tr:nth-child(even) { background: #f9fafb; }
      .status-present { color: #16a34a; font-weight: 600; }
      .status-absent { color: #dc2626; font-weight: 600; }
      .status-other { color: #ca8a04; font-weight: 600; }
      .summary {
        display: grid;
        grid-template-columns: repeat(6, 1fr);
        gap: 5px;
        margin-top: 8px;
        padding: 6px;
        background: #f0f9ff;
        border-radius: 4px;
        border: 1px solid #bae6fd;
      }
      .summary-item { 
        text-align: center; 
        padding: 4px;
        background: white;
        border-radius: 4px;
      }
      .summary-item strong { display: block; font-size: 12px; color: #1e40af; }
      .summary-item span { font-size: 7px; color: #6b7280; }
      .footer {
        margin-top: 10px;
        padding-top: 5px;
        border-top: 1px solid #e5e7eb;
        display: flex;
        justify-content: space-between;
        font-size: 7px;
        color: #9ca3af;
      }
      @media print {
        body { padding: 0; -webkit-print-color-adjust: exact; print-color-adjust: exact; }
        .no-print { display: none; }
        table { page-break-inside: avoid; }
      }
    </style>
  </head>
  <body>
    <div class="header">
      <h1>تقرير الحضور الشهري</h1>
      <p>${format(selectedMonth, "MMMM yyyy", { locale: ar })}</p>
    </div>

    <div class="employee-info">
      <div>
        <strong>اسم الموظف</strong>
        <span>${escapeHtml(employee.name)}</span>
      </div>
      <div>
        <strong>الرقم الوظيفي</strong>
        <span>${escapeHtml(employee.employeeNumber) || "-"}</span>
      </div>
      <div>
        <strong>القسم</strong>
        <span>${escapeHtml(employee.department) || "-"}</span>
      </div>
      <div>
        <strong>المسمى الوظيفي</strong>
        <span>${escapeHtml(employee.position) || "-"}</span>
      </div>
    </div>

    <table>
      <thead>
        <tr>
          <th>التاريخ</th>
          <th>اليوم</th>
          <th>الحالة</th>
          <th>وقت الحضور</th>
          <th>وقت الانصراف</th>
          <th>ساعات العمل</th>
          <th>ملاحظات</th>
        </tr>
      </thead>
      <tbody>
        ${recordRows}
      </tbody>
    </table>

    <div class="summary">
      <div class="summary-item">
        <strong>${summary.presentDays}</strong>
        <span>أيام الحضور</span>
      </div>
      <div class="summary-item">
        <strong>${summary.absentDays}</strong>
        <span>أيام الغياب</span>
      </div>
      <div class="summary-item">
        <strong>${summary.leaveDays}</strong>
        <span>أيام الإجازة</span>
      </div>
      <div class="summary-item">
        <strong>${summary.lateDays}</strong>
        <span>أيام التأخير</span>
      </div>
      <div class="summary-item">
        <strong>${summary.totalWorkHours.toFixed(1)}</strong>
        <span>ساعات العمل</span>
      </div>
      <div class="summary-item">
        <strong>${summary.totalOvertimeHours.toFixed(1)}</strong>
        <span>ساعات الإضافي</span>
      </div>
    </div>

    <div class="footer">
      <span>تم إنشاء التقرير بتاريخ: ${format(new Date(), "dd/MM/yyyy HH:mm", { locale: ar })}</span>
      <span>نظام الموارد البشرية المتقدم</span>
    </div>

    <script>
      window.onload = function() {
        window.print();
      };
    </script>
  </body>
  </html>
`);

const labelHTML = `
  <html dir="rtl">
    <head>
      <meta charset="UTF-8">
      <title>ملصق رول - ${roll.roll_number}</title>
      <style>
        @page { size: 4in 6in; margin: 0; }
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { font-family: 'Arial', sans-serif; direction: rtl; width: 4in; height: 6in; padding: 3mm; }
        .label { width: 100%; height: 100%; border: 2px solid #000; display: flex; flex-direction: column; padding: 3mm; }
        .header { text-align: center; border-bottom: 2px solid #000; padding-bottom: 2mm; margin-bottom: 2mm; }
        .company { font-size: 10pt; font-weight: bold; }
        .roll-num { font-size: 16pt; font-weight: bold; background: #000; color: #fff; padding: 2mm 4mm; margin-top: 1mm; display: inline-block; }
        .content { flex: 1; display: flex; flex-direction: column; gap: 2mm; }
        .row { display: grid; grid-template-columns: 1fr 1fr; gap: 1mm; }
        .box { border: 1px solid #333; padding: 2mm; }
        .box.full { grid-column: 1 / -1; }
        .box.highlight { background: #ffe; border: 2px solid #c90; }
        .lbl { font-size: 7pt; color: #666; font-weight: 600; }
        .val { font-size: 9pt; font-weight: bold; }
        .footer { border-top: 1px solid #333; padding-top: 1mm; text-align: center; font-size: 6pt; color: #666; }
      </style>
    </head>
    <body>
      <div class="label">
        <div class="header">
          <div class="company">نظام إدارة الإنتاج</div>
          <div class="roll-num">${roll.roll_number}</div>
        </div>
        <div class="content">
          <div class="box full"><div class="lbl">العميل</div><div class="val">${roll.customer_name_ar || roll.customer_name || '-'}</div></div>
          <div class="row">
            <div class="box"><div class="lbl">أمر الإنتاج</div><div class="val">${roll.production_order_number}</div></div>
            <div class="box"><div class="lbl">رقم الطلب</div><div class="val">${roll.order_number}</div></div>
          </div>
          <div class="row">
            <div class="box"><div class="lbl">المقاس</div><div class="val">${roll.size_caption || '-'}</div></div>
            <div class="box"><div class="lbl">المرحلة</div><div class="val">${stageConfig.label}</div></div>
          </div>
          <div class="box highlight full"><div class="lbl">الوزن</div><div class="val">${parseFloat(roll.weight_kg).toFixed(2)} كجم</div></div>
          <div class="box full"><div class="lbl">تاريخ الإنتاج</div><div class="val">${format(new Date(roll.created_at), 'dd/MM/yyyy HH:mm')}</div></div>
        </div>
        <div class="footer">طُبع: ${format(new Date(), 'dd/MM/yyyy HH:mm')}</div>
      </div>
    </body>
  </html>
`;
